INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content Briefs$q$, $q$Auto-generated briefs with target word counts, recommended headings, and related topics based on top-ranking competitor content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Topic Modeling$q$, $q$NLP-driven mapping of a subject's related concepts and questions to guide comprehensive topic coverage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content Score$q$, $q$A real-time score estimating how thoroughly a draft covers a topic compared to top-performing competitor pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content Gap Analysis$q$, $q$Identifies missing or thin subtopics across a site so teams can prioritize new content and updates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content Inventory$q$, $q$Connects existing pages to topic clusters to flag cannibalization, decay, and optimization opportunities.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$In-App Editor$q$, $q$A built-in writing environment that tracks content score and topic coverage as text is drafted.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Competitive Research$q$, $q$Analyzes ranking pages for a keyword or topic to surface structure, coverage, and difficulty insights.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$API Access$q$, $q$Programmatic access to briefs, topic models, and scoring data for teams building custom workflows on higher-tier plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Personalized Recommendations$q$, $q$Prioritized topic and content suggestions based on a site's existing inventory and competitive landscape.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Deep topic modeling goes beyond simple keyword targeting to guide comprehensive content coverage$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content briefs give writers and editors clear, data-backed direction before drafting begins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content gap and inventory analysis help prioritize a large backlog of topics efficiently$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Useful for standardizing content strategy across in-house teams or multiple agency clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$API access allows teams to integrate brief and scoring data into their own tooling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Steeper learning curve than lightweight SEO writing tools due to its research-heavy interface$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Less focused on fast, one-click AI draft generation compared to dedicated writing assistants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Can feel like more platform than necessary for very small teams or occasional publishers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Value depends on having an editorial process in place to act on briefs and research$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Pricing sits above many entry-level SEO content tools, which may be a barrier for smaller budgets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$What is MarketMuse used for?$q$, $q$MarketMuse is used for content strategy and SEO content optimization, including generating content briefs, modeling topics, analyzing content gaps, and scoring drafts against top-ranking competitor pages.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Does MarketMuse write content for me?$q$, $q$MarketMuse focuses primarily on research, planning, and optimization rather than fully automated drafting. It provides briefs, topic guidance, and an editor with live scoring, but writers still author the content.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Is there a free version of MarketMuse?$q$, $q$MarketMuse has historically offered a limited free plan alongside paid subscription tiers, letting users try core research and brief features before upgrading for higher usage limits and advanced modules.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Who typically uses MarketMuse?$q$, $q$It is commonly used by SEO managers, content strategists, in-house marketing teams, and agencies that need to plan and prioritize content at scale rather than writing occasional individual articles.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Does MarketMuse integrate with other tools?$q$, $q$MarketMuse supports exporting briefs and research to external tools, and offers API access on higher-tier plans so teams can connect its data to their own CMS or internal workflows.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Building Topic-Cluster Content Strategies$q$, $q$Strategists use MarketMuse's topic modeling and research tools to map an entire subject area and plan a cluster of interlinked pages designed to build topical authority.$q$, $q$SEO strategists and content marketing leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Generating Data-Backed Content Briefs$q$, $q$Editorial teams generate briefs with recommended headings, word counts, and related terms so writers have clear direction before drafting begins.$q$, $q$Content editors and freelance writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Auditing Existing Content for Gaps and Cannibalization$q$, $q$Teams run content inventory and gap analysis to find thin, outdated, or overlapping pages that need consolidation, updates, or new coverage.$q$, $q$In-house SEO teams managing large websites$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Standardizing Client Content Programs$q$, $q$Agencies use MarketMuse to create a consistent brief and scoring process across multiple client accounts, making it easier to demonstrate topic coverage and progress.$q$, $q$SEO and content marketing agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited content briefs and queries","Basic topic research access","Good for evaluating core features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Standard$q$, $q$Starting around $149/month$q$, $q$monthly or annual$q$, $q$["Expanded content briefs and queries","Content optimization and scoring","Core research and inventory tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Team$q$, $q$Starting around $399/month$q$, $q$monthly or annual$q$, $q$["Higher usage limits for briefs and research","Multiple user seats","Advanced content inventory and gap analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Premium / Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, $q$["API access","Custom usage limits","Dedicated support and onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MarketMuse is a content intelligence and optimization platform built around natural language processing and topic modeling. Rather than treating SEO content as a series of one-off keyword targets, MarketMuse maps out entire topic clusters, showing which subtopics, questions, and related concepts a piece of content needs to cover in order to be considered comprehensive by both readers and search engines. This topic-modeling approach has made it a long-standing name in the content strategy and technical SEO space, particularly among teams that publish at scale.$q$, $q$The platform's core workflow revolves around a content brief: users enter a target topic, and MarketMuse analyzes top-ranking pages and its own internal topic model to generate a recommended outline, related terms, target word count, and competitive content scores. Writers and editors can then use that brief inside MarketMuse's own editor or export it to whatever CMS or writing tool the team already uses. A separate research module lets strategists explore an entire topic domain, surfacing content gaps, cannibalization issues, and opportunities to build topical authority across a site.$q$, $q$MarketMuse is positioned less as a lightweight writing assistant and more as an operating layer for content strategy, commonly adopted by in-house SEO teams, content agencies, and publishers that need a repeatable, data-driven process for deciding what to write next, how thoroughly to cover it, and how to prioritize a large backlog of topics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$who-marketmuse-is-for$q$, $q$Who MarketMuse Is For$q$, 2, ARRAY[$q$MarketMuse is best suited for SEO managers, content strategists, and editorial leads who are responsible for planning content at scale rather than writing a single article. Its topic modeling and content scoring tools shine when there are dozens or hundreds of pages to plan, audit, or prioritize, and when decisions need to be justified with data rather than gut feel.$q$, $q$In-house marketing teams at mid-size to enterprise companies, particularly in industries with large content footprints such as SaaS, finance, healthcare, and publishing, tend to get the most value from the platform. Content agencies that manage SEO programs for multiple clients also use MarketMuse to standardize how briefs are produced and to demonstrate topical coverage to stakeholders.$q$, $q$Teams that already have an established editorial workflow and want to layer in more rigorous topic research, gap analysis, and content scoring, without replacing their existing writing or publishing tools, are typically the strongest fit, since MarketMuse is designed to plug into a broader content pipeline rather than serve as the only tool in it.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo bloggers, hobbyists, or very small businesses publishing only a handful of pieces a month may find MarketMuse's depth of topic research and reporting more than they need, especially relative to lighter-weight, cheaper SEO writing tools built for individual authors.$q$, $q$Teams looking primarily for an AI drafting or long-form writing assistant may be better served by tools purpose-built for full first-draft generation, since MarketMuse's writing environment is oriented around optimization and structure guidance rather than being the fastest way to produce finished prose from a single prompt.$q$, $q$Organizations without a documented content or SEO process may also struggle to extract full value, since MarketMuse's briefs and topic models are most useful when there is already a team and workflow in place to act on the recommendations rather than a single person handling content ad hoc.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of MarketMuse is its topic modeling engine, which analyzes large samples of top-performing content for a given subject and builds a map of related concepts, questions, and subtopics. This powers the content brief generator, which produces target word counts, recommended headings, and a content score that estimates how comprehensively a draft covers the topic compared to competitors.$q$, $q$Beyond individual briefs, MarketMuse offers a research module for topic clusters and content gap analysis, helping teams see which subtopics on a domain are missing, thin, or cannibalizing each other, and a personalized content inventory that connects existing pages to topic opportunities. Its own in-app editor lets writers draft directly against a live content score, with metrics updating as text is added.$q$, $q$MarketMuse also supports integrations and exports so briefs and outlines can move into other CMS or documentation tools, along with API access on higher-tier plans for teams that want to embed its scoring and topic data into their own internal content workflows or reporting dashboards.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$the-marketmuse-experience$q$, $q$The MarketMuse Experience$q$, 2, ARRAY[$q$Using MarketMuse typically starts with entering a topic or existing URL, after which the platform surfaces a topic model and a first-pass content brief within moments. The interface leans toward dashboards, scores, and structured tables rather than a conversational chat experience, which fits its positioning as a strategy and planning tool rather than a general-purpose AI writer.$q$, $q$New users generally spend some time getting comfortable interpreting content scores and topic models, since the value of the platform depends on understanding what the scoring actually represents rather than treating it as a simple pass/fail grade. Teams that invest in that ramp-up tend to fold MarketMuse briefs directly into their existing content brief templates and editorial calendars.$q$, $q$Overall, the experience feels like a specialized research and planning layer that sits alongside a team's writing and publishing tools rather than replacing them, with most of the day-to-day interaction happening through briefs, research reports, and score tracking rather than open-ended content generation.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
