INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Lead scoring and grading$q$, $q$Automatically ranks leads by behavioral engagement and firmographic fit so sales can prioritize outreach on the accounts most likely to convert.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Smart campaigns and flow steps$q$, $q$A visual, rule-based engine triggers multi-step nurture programs off form fills, page visits, email clicks, or data changes synced from other systems.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Email marketing and dynamic content$q$, $q$Build and send segmented email programs with personalization tokens and dynamic content blocks that adapt to each recipient's profile.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Landing pages and forms$q$, $q$Create and A/B test landing pages and progressive-profiling forms without needing developer support for most changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$CRM sync (Salesforce and Microsoft Dynamics)$q$, $q$Bidirectional integration keeps lead records, activity history, and campaign membership aligned between marketing and sales systems.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Account-based marketing tools$q$, $q$Score and prioritize target accounts, coordinate multi-contact engagement, and serve account-level personalized content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Revenue-cycle analytics and attribution$q$, $q$Built-in reporting connects marketing programs to pipeline stages and closed revenue, helping justify budget and channel investment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Event and webinar programs$q$, $q$Pre-built program templates manage registration, reminders, and follow-up nurture for in-person and virtual events.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Workspaces and partitions$q$, $q$Segment assets, users, and data by region, brand, or business unit while still reporting across the whole organization from one instance.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Predictive content and personalization$q$, $q$Surfaces recommended content to prospects based on similar-visitor behavior to keep nurture streams relevant as interests evolve.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Deep, mature Salesforce and Microsoft Dynamics integrations keep sales and marketing data aligned$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Powerful, flexible automation engine handles complex, multi-channel nurture logic at enterprise scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Strong account-based marketing and lead-scoring capabilities suited to long B2B sales cycles$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Large practitioner community, certification program, and partner ecosystem make it easier to find skilled help$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Fits naturally alongside other Adobe Experience Cloud products for teams already in that ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Steep learning curve; the program, workspace, and smart-list data model takes real time to master$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Pricing is not published and typically requires a sales conversation and annual contract$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Interface feels dated and admin-heavy compared to newer, simpler marketing automation tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Best value usually requires a CRM already in place plus dedicated marketing operations staff$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Implementation and ongoing administration often require certified specialists or an agency partner$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$What is Marketo Engage used for?$q$, $q$Marketo Engage is a B2B marketing automation platform used for capturing, scoring, nurturing, and handing off leads to sales, along with running email campaigns, landing pages, events, and account-based marketing programs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$How much does Marketo Engage cost?$q$, $q$Adobe does not publish pricing publicly. Cost depends on factors like database size, modules selected, and contract length, so prospective customers need to contact Adobe sales for a custom quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Is Marketo Engage part of Adobe?$q$, $q$Yes. Marketo was founded independently in 2006 and acquired by Adobe in 2018; it now operates as Marketo Engage within Adobe Experience Cloud.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Does Marketo Engage integrate with Salesforce?$q$, $q$Yes, Marketo Engage offers a native, bidirectional Salesforce integration that syncs leads, contacts, campaign membership, and activity history between the two systems, and it also integrates with Microsoft Dynamics.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Is Marketo Engage suitable for small businesses?$q$, $q$Generally no. It is built for mid-market and enterprise B2B organizations with dedicated marketing operations resources; small teams or simple B2C use cases are usually better served by lighter-weight tools.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Multi-touch lead nurturing$q$, $q$Automatically guide new prospects through a sequence of emails and content based on their behavior and score until they are ready for sales follow-up.$q$, $q$B2B marketing teams with long consideration cycles$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Account-based marketing programs$q$, $q$Identify and score target accounts, coordinate personalized outreach across multiple contacts, and align sales and marketing around the same account list.$q$, $q$Enterprise sales and marketing teams targeting named accounts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Revenue attribution and reporting$q$, $q$Connect campaign and program activity to pipeline stages and closed-won revenue so marketing can demonstrate ROI to leadership and finance.$q$, $q$Marketing operations and RevOps leaders$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Event and webinar follow-up$q$, $q$Manage registration, reminders, and post-event nurture streams that route engaged attendees into the next stage of the sales funnel.$q$, $q$Field and demand generation marketers running events$q$, 3);
