INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Prime$q$, $q$Contact sales$q$, $q$Annual contract$q$, $q$["Account-based marketing tools","Predictive content","Revenue-cycle analytics","Workspaces and partitions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Ultimate$q$, $q$Contact sales$q$, $q$Annual contract$q$, $q$["Full ABM and predictive suite","Advanced attribution reporting","Deeper Adobe Experience Cloud integration","Premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Marketo Engage is a business-to-business marketing automation platform originally built by Marketo Inc., founded in 2006, and acquired by Adobe in 2018, where it now anchors the marketing-automation layer of Adobe Experience Cloud alongside tools like Analytics, Target, and Real-Time CDP. It gives marketing operations teams a single system for capturing, scoring, nurturing, and routing leads to sales, with the goal of shortening sales cycles and making marketing's contribution to pipeline measurable rather than anecdotal.$q$, $q$The platform's core loop is lead lifecycle management: prospects are captured through landing pages and forms, scored and graded against an ideal customer profile, then guided through automated, multi-channel nurture programs spanning email, web personalization, events, and paid media until they are judged sales-ready. Deep, native integrations with Salesforce and Microsoft Dynamics keep marketing engagement data synced with sales pipelines in near real time, so reps see exactly what a prospect has viewed, opened, or clicked before ever picking up the phone.$q$, $q$Because Marketo Engage was built for enterprise scale rather than for simplicity, it emphasizes governance, security, and reporting over out-of-the-box ease of use: workspaces and partitions let large organizations run many regional, brand, or business-unit programs from one shared instance, while revenue-cycle analytics tie marketing activity back to pipeline and closed-won revenue for finance and executive leadership.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$who-marketo-engage-is-for$q$, $q$Who Marketo Engage Is For$q$, 2, ARRAY[$q$Marketo Engage suits mid-market and enterprise B2B companies with a dedicated marketing operations function that needs to orchestrate complex, multi-touch demand generation across email, web, events, and paid channels while staying tightly synced with a CRM. It rewards teams willing to invest ongoing time in administration, list hygiene, and program maintenance rather than looking for a quick, self-serve setup.$q$, $q$Account-based marketing teams get particular value from account-level scoring, dynamic content, and bidirectional Salesforce or Dynamics sync that gives sales reps visibility into prospect engagement history at both the individual and account level. Organizations with long, multi-stakeholder sales cycles also benefit, since lead scoring and nurture streams help marketing and sales agree on which contacts and accounts deserve attention first.$q$, $q$Companies already standardized on Adobe Experience Cloud tools such as Analytics, Target, or Real-Time CDP gain extra leverage, because Marketo shares data models and audience definitions with those products, letting marketing ops build a more unified customer profile across web, email, and advertising touchpoints without rebuilding audiences separately in every tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, solo marketers, and lean teams without a dedicated marketing operations role will likely find Marketo Engage more platform than they need, since it assumes ongoing configuration, list hygiene, and program maintenance rather than a drop-in, self-service tool a single marketer can run casually.$q$, $q$Teams wanting transparent, low-cost, self-serve pricing, or a lightweight email and automation tool for simple B2C use cases, are usually better served by simpler platforms. Marketo's program, workspace, and smart-list data model carries a genuine learning curve that a casual or occasional user is unlikely to need.$q$, $q$Organizations without an existing CRM, or without budget for implementation and onboarding, often struggle with Marketo Engage, since much of its value comes from tight sales-and-marketing alignment and from setup work that typically involves certified administrators, consultants, or an agency partner rather than a same-day install.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Marketo Engage combines lead management, email marketing, and program automation: marketers build multi-step nurture and drip campaigns using a visual flow-step engine, triggered by form fills, page visits, email engagement, or custom data changes pushed in from other systems, with branching logic based on behavior and lead score.$q$, $q$Lead scoring and grading let teams weight both behavioral engagement and firmographic fit, automatically routing sales-ready leads to CRM queues, while smart lists and dynamic segments keep audiences current without manual list rebuilding as contact data changes, reducing the ongoing maintenance burden on the marketing ops team.$q$, $q$Beyond nurture, the platform includes landing pages and forms, event and webinar program templates, account-based marketing tools for target-account scoring and personalization, predictive content recommendations, and revenue-cycle analytics and attribution reporting that connect campaign activity to pipeline and revenue outcomes.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$the-marketo-engage-experience$q$, $q$The Marketo Engage Experience$q$, 2, ARRAY[$q$Day to day, Marketo Engage is administered through a dense, admin-oriented interface built around programs, smart campaigns, and smart lists rather than a simple drag-and-drop canvas, which gives it real power and flexibility but asks new users to learn its vocabulary and underlying data model before becoming fully productive.$q$, $q$Adobe backs the product with a large practitioner community, the Marketing Nation user groups and forums, a certification program for administrators, and an extensive partner and agency ecosystem, which together make it easier for organizations to hire experienced in-house talent or outsource complex build-outs to a trusted partner.$q$, $q$Reporting lives in built-in dashboards, including revenue-cycle and program-performance views, and can extend further through Adobe Experience Cloud connections; most teams pair Marketo Engage with a CRM and a business-intelligence tool to get a complete, board-ready view of how marketing programs contribute to pipeline and revenue over time.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
