INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Usability Testing$q$, $q$Run task-based usability tests against prototypes or live products and see where testers succeed, struggle, or drop off.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Prototype Testing$q$, $q$Import prototypes directly from Figma, Adobe XD, or Sketch and test them with real users without recreating flows manually.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Five-Second Testing$q$, $q$Show a design for a few seconds to measure first impressions, memorability, and initial comprehension.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Card Sorting$q$, $q$Understand how users mentally group content and terminology to inform navigation and information architecture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Tree Testing$q$, $q$Validate a proposed site or app structure by asking testers to locate items within a simplified navigation tree.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Live Website Testing$q$, $q$Test an already-shipped website or web app using its real URL instead of only pre-launch prototypes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Surveys$q$, $q$Collect standalone qualitative and quantitative feedback with customizable survey questions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Participant Recruiting$q$, $q$Recruit external testers matching target demographics when an internal user base isn't available or sufficient.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Automated Reporting & AI Insights$q$, $q$Get auto-generated reports with heatmaps, completion rates, and AI-assisted summaries of open-ended responses.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Fast to set up and launch a first test without deep research training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Supports many test types in a single connected platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Strong integrations with popular design tools like Figma$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Reports are visual and easy to share with non-researcher stakeholders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Free plan makes it easy to try before committing to a subscription$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Less depth and flexibility than specialist moderated-research tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Free and lower tiers cap monthly tests or responses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Built-in participant panel may not cover niche or specialized audiences$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Advanced features and higher volume require moving to paid tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Enterprise-grade customization typically requires contacting sales$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$What is Maze used for?$q$, $q$Maze is used to run user testing and product research studies, such as usability tests, prototype tests, five-second tests, card sorts, tree tests, and surveys, to validate designs and products with real users.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Does Maze integrate with design tools?$q$, $q$Yes, Maze integrates directly with tools like Figma, Adobe XD, and Sketch, allowing teams to import prototypes and test them without rebuilding the design elsewhere.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Is there a free version of Maze?$q$, $q$Maze offers a free plan with limited monthly testing capacity, along with paid plans that unlock higher volumes and additional features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Do I need a background in UX research to use Maze?$q$, $q$No, Maze is designed to be usable by designers, product managers, and marketers without formal research training, though experienced researchers can also use its more advanced test configurations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Can Maze recruit testers for me?$q$, $q$Yes, Maze offers participant recruiting so teams without their own user base can find testers matching general target criteria, in addition to testing with your own users.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Validating a Prototype Before Development$q$, $q$Product teams import a Figma or Sketch prototype into Maze and run a usability test to confirm a flow works before engineering resources are committed.$q$, $q$Product designers and product managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Testing First Impressions of a New Design$q$, $q$Teams use five-second tests to see what users notice and recall first from a homepage, ad creative, or app screen.$q$, $q$Marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Improving Site Navigation$q$, $q$Researchers run card sorting and tree testing studies to reorganize navigation and menu structures based on how users naturally group content.$q$, $q$UX researchers and information architects$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Validating a Live Website or App$q$, $q$Teams run live website tests on an already-shipped product to catch usability issues that surface only in the real environment.$q$, $q$Startups and in-house product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, $q$["Limited monthly tests and responses","Core test types (usability, prototype, five-second)","Basic reporting","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Starter$q$, $q$From $99/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Higher monthly testing volume","Prototype and live website testing","Basic integrations","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Growth$q$, $q$Contact for pricing$q$, $q$Monthly or annual$q$, $q$["Expanded testing volume","Card sorting and tree testing","Team collaboration features","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Organization$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Custom volume and seats","Advanced admin and security controls","Dedicated account support","Custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maze is a user testing and product research platform that lets teams validate designs, prototypes, and live products by putting them in front of real users and gathering structured feedback. Rather than relying on guesswork or subjective internal reviews, teams create a test project built around specific tasks, questions, or a design pulled directly from a prototyping tool, then share it with testers who complete it remotely.$q$, $q$The platform supports several research methods in one place, including usability testing, prototype testing pulled from tools like Figma, Adobe XD, and Sketch, five-second tests for gauging first impressions, card sorting and tree testing for information architecture, and surveys for gathering broader qualitative and quantitative feedback. Results are compiled automatically into visual reports with completion rates, heatmaps, misclick data, and open-ended responses, cutting out much of the manual work traditionally required to synthesize usability findings.$q$, $q$Maze positions itself as a way to make user research faster and more continuous rather than an occasional, heavyweight exercise reserved for dedicated researchers. It offers a free plan alongside paid tiers, and its target audience spans solo designers, in-house UX research teams, and cross-functional product organizations that want design and product decisions backed by real user behavior rather than internal opinion.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$who-maze-is-for$q$, $q$Who Maze Is For$q$, 2, ARRAY[$q$Maze is well suited to UX researchers and product designers who need to validate flows, wireframes, or high-fidelity prototypes before development resources are committed. Its direct integrations with common design tools make it straightforward to import an existing prototype and start collecting structured feedback the same day, without needing testers to have any special software or training.$q$, $q$Product managers and startup teams also get real value from Maze, particularly when they need quick directional feedback on a new feature or flow and don't have a dedicated research function to lean on. The combination of ready-made test templates and an accessible, largely self-serve interface means non-researchers can run a reasonably rigorous test without first learning formal usability research methodology.$q$, $q$Growth and marketing teams use Maze as well, mainly for testing landing pages, onboarding flows, and messaging with five-second tests or live website studies before a wider launch. Teams that already run a steady cadence of product experiments tend to get the most value from the platform, since the tooling rewards frequent, iterative testing rather than a single one-off study.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Research teams that require deeply moderated, one-on-one qualitative sessions with heavy custom scripting, or that depend on specialized panels for narrow demographic or clinical populations, may find Maze's built-in recruiting and structured test formats too generalized for their needs and will likely still need a dedicated moderated-interview tool or specialist recruiting partner.$q$, $q$Organizations with strict procurement, data residency, or compliance requirements that need extensive customization of contracts, security reviews, or dedicated deployment arrangements should validate those requirements directly with Maze's sales team before committing, since self-serve plans are built around standard terms rather than bespoke enterprise arrangements.$q$, $q$Individuals or very small teams looking for a permanently free, full-featured testing tool may also be frustrated, since the free tier is intentionally limited to encourage upgrading once testing volume or advanced analysis needs grow; teams unwilling to eventually pay for a subscription may outgrow the free plan faster than expected.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Maze supports a range of test types under one roof: usability testing and prototype testing against imported Figma, Sketch, or Adobe XD files, five-second tests for first-impression and recall feedback, and card sorting and tree testing for evaluating navigation and information architecture. Each format is built around guided task flows and follow-up questions rather than free-form observation.$q$, $q$Beyond the core test types, Maze offers live website testing so teams can validate an already-shipped site or product rather than only pre-launch prototypes, plus surveys for standalone feedback collection. Its panel recruiting feature can help teams find external testers matching target demographics when they don't have their own user base to draw from, complementing the option to test with your own users or customer lists.$q$, $q$Results are turned into automatically generated reports that include heatmaps, click paths, completion and success rates, and verbatim responses, and Maze has layered in AI-assisted analysis to help summarize open-ended feedback and surface themes faster. Integrations with tools like Slack, Notion, Jira, and common design and product-management software help route findings into existing workflows rather than leaving them siloed in a separate reporting tool.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$the-maze-experience$q$, $q$The Maze Experience$q$, 2, ARRAY[$q$Setting up a first test in Maze is generally quick: connecting a design file or entering a URL, adding tasks and questions from a template or from scratch, and sharing a link to testers can be done within a single sitting, which is part of why the platform appeals to teams without dedicated research tooling experience.$q$, $q$Collaboration is built around shareable reports and dashboards, so designers, product managers, and stakeholders can review results and highlights without needing their own Maze login for every action. This lowers the friction of getting research findings actually seen and acted on by a wider team rather than staying locked inside a researcher's personal files.$q$, $q$Overall, the experience trades some of the depth and flexibility of specialist qualitative research tools for speed and accessibility. It is built to make running a test feel closer to sending a survey than commissioning a research study, which is exactly what makes it appealing for teams that want to test early and often rather than occasionally and exhaustively.$q$]::text[], 4);
