INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Real-Time Antivirus Scanning$q$, $q$Continuously monitors files and downloads for malware, ransomware, and other threats as they appear.$q$, 0);
