INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Multi-Device Dashboard$q$, $q$Provides a single view of protection status across all devices linked to an account.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$PC Performance Optimization$q$, $q$Includes tools aimed at cleaning up junk files and improving system speed.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Bundles antivirus, VPN, and identity monitoring into one subscription$q$, 0);
