INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$AI-Powered Sentiment Analysis$q$, $q$Automatically classifies mentions as positive, negative, or neutral and clusters related topics to speed up analysis.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Media Contacts Database$q$, $q$A searchable directory of journalists and outlets that supports targeted PR outreach and relationship building.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Influencer Discovery$q$, $q$Helps marketing teams find, vet, and evaluate influencers based on audience and past content performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Custom Dashboards and Reporting$q$, $q$Configurable, shareable dashboards let teams present monitoring data in formats suited to different stakeholders.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Competitive Benchmarking$q$, $q$Compares share of voice, sentiment, and coverage volume against named competitors over time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Real-Time Alerts$q$, $q$Notifies teams by email or app when mention volume or sentiment shifts unexpectedly, supporting faster crisis response.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Consumer and Market Insights$q$, $q$Extends monitoring data into broader audience and industry trend analysis for strategic planning.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0e66535-3ff0-4403-abac-5c27a5f34b18', $q$Mobile App Access$q$, $q$Lets communications teams review coverage, alerts, and reports from iOS and Android devices while away from a desktop.$q$, 9);
