INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Real-time media monitoring$q$, $q$Tracks brand, product, or competitor mentions across news sites, blogs, forums, and review sites as they're published.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Social listening$q$, $q$Monitors major social networks for mentions, hashtags, and conversations relevant to configured keywords.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Sentiment analysis$q$, $q$Automatically classifies mentions as positive, negative, or neutral to help prioritize responses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Boolean alert builder$q$, $q$Lets users construct precise search queries with operators to reduce noise and focus on relevant mentions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Influencer identification$q$, $q$Surfaces the authors and accounts generating the most reach or engagement around a topic.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Unified inbox$q$, $q$Centralizes mentions and social replies in one stream so teams can tag, assign, and respond without switching tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Reporting and share-of-voice dashboards$q$, $q$Generates exportable reports comparing mention volume and sentiment against competitors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Social publishing and scheduling$q$, $q$Allows scheduling and publishing posts to connected social accounts from within the platform.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Mobile apps$q$, $q$iOS and Android apps let teams check alerts and respond to mentions away from a desktop.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Team collaboration tools$q$, $q$Supports assigning mentions to teammates and multi-brand or multi-client account structures for agencies.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Fast, near real-time alerting on new mentions across web and social sources$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Sentiment analysis helps quickly triage what needs a response$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Combines monitoring with lightweight social publishing in one subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Multi-brand setup is convenient for agencies managing several clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Mobile apps make it easy to monitor and respond on the go$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$No permanent free plan, only a limited-time free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Boolean query syntax has a learning curve for new users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Historical data depth may be limited compared to enterprise listening tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Pricing can scale up quickly for teams needing higher mention volumes or more alerts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Publishing features are secondary and less robust than dedicated social media management tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$What is Mention used for?$q$, $q$Mention is used for monitoring brand, product, and competitor mentions across news sites, blogs, forums, and social media, with sentiment analysis and reporting to track reputation over time.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Does Mention offer a free plan?$q$, $q$Mention offers a free trial rather than a permanent free plan; ongoing use requires a paid subscription.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Can Mention track social media mentions in real time?$q$, $q$Yes, Mention continuously scans social networks and web sources for matching keywords and delivers new mentions to a live stream shortly after they're published.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Is Mention suitable for agencies managing multiple clients?$q$, $q$Yes, Mention supports multi-brand configurations, letting agencies track and report on several client accounts within one workspace.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Does Mention include social media publishing?$q$, $q$Yes, Mention includes basic scheduling and publishing tools alongside its core monitoring and listening features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Brand reputation monitoring$q$, $q$Track ongoing mentions of a company or product to catch reputation shifts and respond to negative sentiment quickly.$q$, $q$Marketing and communications teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$PR campaign tracking$q$, $q$Measure media pickup and social reaction following a press release, launch, or announcement.$q$, $q$PR professionals and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Competitive intelligence$q$, $q$Compare share of voice and sentiment against named competitors to inform positioning and messaging.$q$, $q$Product marketers and strategists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Crisis and issue monitoring$q$, $q$Detect spikes in negative mentions early so teams can respond before an issue escalates.$q$, $q$Communications and social media managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Solo$q$, $q$~$41/month$q$, $q$Monthly or annual (annual discounted)$q$, $q$["Limited alerts and keywords","Basic sentiment analysis","Mobile app access","Social publishing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Pro$q$, $q$~$83/month$q$, $q$Monthly or annual (annual discounted)$q$, $q$["More alerts and mentions per month","Team collaboration","Advanced reporting","Influencer identification"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Company$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Higher mention volume limits","Multi-brand management","Priority support","Custom reporting exports"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, $q$["Custom mention volume and alert limits","Dedicated account support","Advanced integrations","Tailored onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mention is a media monitoring and social listening platform built to help brands, agencies, and individuals track what's being said about them across the web. It crawls news sites, blogs, forums, and social networks in near real time, surfacing mentions of a brand, product, competitor, or industry keyword the moment they appear.$q$, $q$Beyond simple alerts, Mention layers on sentiment analysis, influencer identification, and reporting tools so teams can turn raw mentions into an understanding of how their reputation is trending. A unified inbox lets users read, tag, and respond to conversations without switching between multiple social and search tools.$q$, $q$The platform also includes lightweight social publishing and scheduling features, positioning it as a hybrid between a pure listening tool and a social media management suite. This combination makes it a practical entry point for teams that want monitoring and a bit of outbound social activity in one subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$who-mention-is-for$q$, $q$Who Mention Is For$q$, 2, ARRAY[$q$Mention is aimed at marketing, PR, and communications teams that need to keep a pulse on brand perception without building a custom monitoring stack. Solo marketers, freelancers, and small agencies often use it to track a handful of clients or campaigns at a manageable price point.$q$, $q$Growing brands launching products, running PR campaigns, or managing a crisis benefit from the near real-time alerting, since catching a spike in negative sentiment early can materially change how a situation is handled. Community managers who need one inbox for social replies and web mentions also find the workflow useful.$q$, $q$Agencies managing multiple client accounts can use Mention's multi-brand setup and reporting exports to demonstrate share-of-voice and sentiment trends to stakeholders, making it a fit for teams that need to justify PR and marketing spend with concrete monitoring data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with sophisticated social listening requirements, such as deep historical data archives, advanced natural-language-processing customization, or enterprise-grade data governance, may find dedicated enterprise listening suites better suited to their scale, even though Mention offers a custom enterprise tier.$q$, $q$Teams that only need basic social media scheduling and publishing, without any monitoring component, are likely better served by a dedicated social media management tool, since Mention's publishing features are secondary to its listening core.$q$, $q$Budget-conscious individuals or hobbyist projects that only need occasional keyword checks may find the recurring subscription cost hard to justify compared to free alternatives like manual social search or basic Google Alerts, especially if mention volume is low.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Mention lets users set up Boolean-style search queries (alerts) that continuously scan news, blogs, forums, and social platforms for matching mentions, delivering results into a unified stream that can be filtered by source, sentiment, or reach.$q$, $q$Sentiment analysis tags mentions as positive, negative, or neutral automatically, helping teams prioritize what to respond to first, while influencer and reach metrics highlight which authors or accounts are driving the most visibility around a topic.$q$, $q$Reporting tools let teams export dashboards and share-of-voice comparisons against competitors, and a social publishing module allows scheduling posts directly from the same interface, rounding out the platform as both a listening and lightweight action tool.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$the-mention-experience$q$, $q$The Mention Experience$q$, 2, ARRAY[$q$Setting up Mention typically starts with creating an alert around a brand name, product, or competitor, after which the platform begins populating a feed of matching mentions within minutes. The interface groups conversations by source type, making it easy to separate news coverage from social chatter.$q$, $q$Day to day, users spend most of their time in the mention stream and inbox, tagging items, assigning them to teammates, and replying to social posts without leaving the app. The dashboard and reporting views are generally reserved for weekly or monthly reviews, where sentiment trends and competitor comparisons are pulled together.$q$, $q$New users generally find the core alerting and inbox workflow intuitive, though getting the most value out of Boolean query syntax and filtering options takes a bit of experimentation. Mobile apps extend the monitoring experience so alerts can be checked on the go rather than only at a desk.$q$]::text[], 4);
