INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Multi-Network Scheduling & Publishing$q$, $q$Plan and auto-publish posts to Instagram, Facebook, TikTok, X, LinkedIn, Pinterest, YouTube, and Google Business Profile from one visual content calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Analytics & Custom Reports$q$, $q$Track engagement, reach, and follower growth across networks, then package results into automated, brandable reports for clients or stakeholders.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Competitor Analysis$q$, $q$Benchmark your accounts against competitors by tracking their public posting activity, engagement, and growth trends over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Social Inbox$q$, $q$Reply to comments, mentions, and direct messages from multiple connected networks in a single unified inbox view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Smart Link (Link in Bio)$q$, $q$Build a customizable link-in-bio microsite to drive traffic from social profiles to websites, products, or other content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Ads Reporting & Management$q$, $q$View and manage Meta and Google Ads campaign performance alongside organic social metrics in the same dashboard.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$AI Content Assistant$q$, $q$Generate caption drafts, hashtag ideas, and content suggestions with a built-in AI assistant to speed up content creation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Best Time to Post$q$, $q$Get data-driven recommendations on optimal posting times for each connected profile based on historical engagement patterns.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Team Collaboration & Approval Workflows$q$, $q$Assign roles, route content through approval steps, and manage client or team access with permission-based collaboration tools.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$API & Looker Studio Connector$q$, $q$Pull Metricool data into custom dashboards or spreadsheets using the API or a native Looker Studio connector for advanced reporting.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Generous free plan that covers real scheduling and analytics needs for a single brand$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Combines organic social scheduling, analytics, and paid ad reporting in one dashboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Pricing scales by number of brands, which suits agencies managing multiple clients$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$White-label reporting and approval workflows are well suited to agency use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Broad network coverage including less commonly supported platforms like Google Business Profile$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Dense interface takes some time to fully learn given how many reports and settings are available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Some advanced features, like deeper campaign dashboards, are reserved for higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Certain network connections, such as LinkedIn and X, can carry additional add-on costs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Mobile apps cover core actions but are lighter than the full desktop reporting experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Custom plan pricing for very large brand portfolios requires contacting sales rather than self-serve checkout$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Does Metricool have a free plan?$q$, $q$Yes, Metricool offers a free plan for managing one brand that includes post scheduling, basic analytics, and limited competitor tracking, usable for as long as needed without a credit card.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Which social networks does Metricool support?$q$, $q$Metricool supports Instagram, Facebook, TikTok, X, LinkedIn, Pinterest, YouTube, and Google Business Profile, alongside Google Ads and Meta Ads reporting.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$How much does Metricool cost?$q$, $q$Paid plans start at roughly $20 per month and scale up based on the number of brands and advanced features needed, with a Custom plan available for large agencies that requires contacting sales.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Is Metricool suitable for agencies managing multiple clients?$q$, $q$Yes, Metricool supports managing many brands from one account, white-label reporting, and approval workflows, which are commonly used by agencies handling several client accounts at once.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Does Metricool offer an API?$q$, $q$Metricool provides an API and a Looker Studio connector on its higher-tier plans, allowing teams to pull analytics data into custom dashboards or spreadsheets.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Managing a single small business's social presence$q$, $q$A local business owner schedules posts across Instagram and Facebook, checks basic engagement analytics, and tracks a handful of competitors, all from the free plan.$q$, $q$Small business owners and solopreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Running social accounts for multiple clients$q$, $q$A social media manager schedules content and monitors performance across dozens of brand profiles, using role-based access to keep each client's data organized.$q$, $q$Freelance social media managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Delivering white-label client reporting$q$, $q$A marketing agency automates recurring, branded performance reports for each client account, reducing manual reporting work while keeping data client-ready.$q$, $q$Marketing and social media agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Unifying organic and paid social reporting$q$, $q$A performance marketer reviews Meta and Google Ads results next to organic post engagement in one dashboard to understand overall social ROI.$q$, $q$Paid social and performance marketers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, $q$["Manage 1 brand","Schedule up to 20 posts per month","Analyze up to 5 competitor profiles","30 days of analytics storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Starter$q$, $q$From around $20/month$q$, $q$Monthly or annual (annual saves more)$q$, $q$["Up to 10 brands","Unlimited content publishing","Analyze up to 100 competitors","LinkedIn connection included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Advanced$q$, $q$From around $53/month$q$, $q$Monthly or annual (annual saves more)$q$, $q$["Manage up to 50 brands","Team and client management with approvals","Customizable report templates","API access and Looker Studio connector"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$Custom$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Custom number of brands","White-label option","Dedicated account manager","Custom AI assistant credits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Metricool is a social media management and analytics platform built to bring publishing, reporting, and paid ad tracking together in one workspace. Instead of switching between separate scheduling tools, native network dashboards, and spreadsheets, users can plan content, review performance, and monitor competitors from a single interface that updates across every connected profile in near real time.$q$, $q$The platform grew out of the need marketers and small business owners had for an affordable alternative to enterprise social suites like Hootsuite or Sprout Social. Metricool leans into simplicity and value, offering a genuinely usable free tier alongside paid plans that scale with the number of brands and team members a business needs to manage, which has made it popular with agencies and solo marketers alike.$q$, $q$At its core, Metricool combines a content calendar, analytics engine, and ad reporting layer for platforms including Instagram, Facebook, TikTok, X, LinkedIn, Pinterest, YouTube, and Google Business Profile. It also bundles a link-in-bio tool, competitor benchmarking, and an AI assistant for caption and idea generation, positioning itself as a practical hub rather than a single-purpose scheduler.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$who-metricool-is-for$q$, $q$Who Metricool Is For$q$, 2, ARRAY[$q$Metricool is a strong fit for small and mid-sized businesses that need to run a consistent social presence without hiring a dedicated analytics team. Its free plan and low-cost entry tiers make it accessible to solopreneurs, local businesses, and content creators who want scheduling and reporting without committing to an expensive contract upfront.$q$, $q$Social media managers juggling several brands or client accounts also benefit, since the platform is built around managing many profiles from one login. Agencies in particular gain from white-label reporting, client-ready dashboards, and approval workflows that let account managers keep clients informed without exporting data manually into other design tools.$q$, $q$Marketers who run paid social campaigns alongside organic content will appreciate that Metricool pulls in ad performance data next to organic metrics, giving a fuller picture of what is driving engagement or conversions. Teams that value straightforward pricing tied to the number of brands, rather than opaque per-seat enterprise contracts, tend to find Metricool a comfortable long-term home.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises that need deep social listening, sentiment analysis at scale, or dedicated customer-service style inboxes with ticketing and escalation may find Metricool's toolset lighter than what specialized platforms in that category provide. Organizations with strict compliance or multi-level approval hierarchies spanning legal, brand, and regional teams might also outgrow its collaboration features.$q$, $q$Businesses looking for a single tool that also covers email marketing, CRM, or broader marketing automation should look elsewhere, since Metricool's focus stays on social media, its analytics, and ad reporting rather than the full marketing stack. Teams already deeply invested in another suite with custom integrations built around it may not see enough benefit to justify switching.$q$, $q$Companies that manage an unusually high number of brands or need highly customized workflows may find that some capabilities sit behind the higher-tier Custom plan, which requires a sales conversation rather than transparent self-serve pricing. If predictable, fully published pricing at every tier is a hard requirement, that gap is worth weighing before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Metricool's foundation is its scheduling and publishing engine, which supports direct posting to the major social networks along with a visual content calendar, best-time-to-post suggestions, and bulk scheduling via spreadsheet import. Analytics sit right alongside publishing, turning raw engagement numbers into shareable, customizable reports that can be automated on a recurring basis for clients or internal stakeholders.$q$, $q$Beyond the core loop of planning and measuring, the platform layers in competitor analysis to benchmark growth and engagement against other accounts, a unified social inbox for replying to comments and messages across networks, and a link-in-bio microsite builder for driving traffic from social profiles. Ads reporting pulls in spend and performance data from Meta and Google campaigns so paid and organic results live in one place.$q$, $q$Collaboration features round out the feature set, including post approval workflows, role-based access for team members and clients, an AI assistant for drafting captions and generating content ideas, and an API plus Looker Studio connector for teams that want to build custom dashboards on top of Metricool's data.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', $q$the-metricool-experience$q$, $q$The Metricool Experience$q$, 2, ARRAY[$q$New users typically start by connecting their social profiles and Google Business or ad accounts, after which Metricool populates its dashboards with historical data almost immediately. The onboarding flow is guided enough that non-technical users can get a calendar populated and a first report generated within their first session, without needing a lengthy setup process.$q$, $q$The interface favors a dense, data-forward layout over minimalist design, which means there is a short learning curve to find every report or setting, but most day-to-day actions like scheduling a post or checking analytics feel quick once the layout is familiar. Mobile apps let users approve posts, check quick stats, and respond to messages on the go, though the deepest reporting still lives on the desktop dashboard.$q$, $q$Overall, the day-to-day experience centers on moving fluidly between planning content and reviewing how it performed, which is where Metricool differentiates itself from tools that treat scheduling and analytics as separate products. Support is available through in-app chat and a help center, and the platform ships regular updates as social networks change their APIs and ad formats.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0af4f822-0c8a-4a66-b0ae-4dcb5e2d9f6b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
