-- ── MarketMuse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$AI-powered content intelligence platform that helps teams research, plan, write, and optimize SEO content at scale.$q$,
  pricing_model = $q$Freemium$q$,
  starting_price = $q$Free plan available; paid plans start around $149/month billed annually$q$,
  founded_year = 2012,
  company_size = NULL,
  headquarters = $q$Boston, Massachusetts, USA$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$MarketMuse review: AI content intelligence for topic modeling, content briefs, and SEO optimization. Pricing, features, pros and cons.$q$,
  og_description = $q$MarketMuse review: AI content intelligence for topic modeling, content briefs, and SEO optimization. Pricing, features, pros and cons.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b77c4b21-5cd3-47b0-a144-34c9f0369acb';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'b77c4b21-5cd3-47b0-a144-34c9f0369acb' AND logo IS NULL AND website IS NOT NULL;









